INSERT INTO ads (user_id, brand, model, year, price, description, image_path, status) VALUES
(1, 'Toyota', 'Camry', 2020, 15500000, 'Көліктің жағдайы өте жақсы, 70-ші кузов. Ешқандай жөндеуді қажет етпейді. Майы мен сүзгілері уақытылы ауыстырылған. Тек қалада мінілген.', 'images/cars/camry.jpg', 'active'),
(2, 'Hyundai', 'Accent', 2018, 6800000, 'Қала ішінде айдауға өте ыңғайлы әрі үнемді көлік. Таксиде болмаған, тек жұмыс пен үй арасында айдалған. Капоттың қасында кішкене саудасы бар.', 'images/cars/accent.jpg', 'active'),
(1, 'Kia', 'Rio', 2019, 7200000, 'Жағдайы тамаша, іші таза. Бір ғана иесі болған. Қысқы дөңгелектері сыйлыққа беріледі.', 'images/cars/rio.jpg', 'active'),
(2, 'BMW', '5 Series', 2016, 12500000, 'Нағыз ер адамның көлігі. Қозғалтқышы мен қорабы мінсіз жұмыс істеп тұр. Апатқа ұшырамаған, өз бояуында (родная краска).', 'images/cars/bmw5.jpg', 'active'),
(1, 'Mercedes-Benz', 'E-Class', 2021, 28000000, 'Көлік жаңа, ресми дилерден сатып алынған. Кепілдікте тұр. Толық жиынтық (полная комплектация), AMG пакет. Салоны өте таза.', 'images/cars/mercedes_e.jpg', 'active'),
(2, 'Lada (ВАЗ)', 'Granta', 2015, 2800000, 'Күнделікті шаруаға таптырмас сенімді көлік. Моторы май жемейді, жүрісі жұмсақ. Нақты аларманға жақсы жеңілдік жасаймын.', 'images/cars/granta.jpg', 'active'),
(1, 'Lexus', 'RX 300', 2020, 27500000, 'Керемет кроссовер. Іші кең әрі жайлы, былғары салоны мінсіз күйде. Ешқандай сырылған немесе соғылған жері жоқ, кез-келген тексеріске дайын.', 'images/cars/rx300.jpg', 'active'),
(2, 'Toyota', 'Land Cruiser Prado', 2018, 23000000, 'Жол талғамайтын нағыз сенімді көлік. 4 литрлік қозғалтқыш. Жаңа жазғы дөңгелектер орнатылған. Ақша қажет болғандықтан шұғыл сатылып жатыр.', 'images/cars/prado.jpg', 'active'),
(1, 'Volkswagen', 'Polo', 2017, 5500000, 'Экономикалық жағынан өте тиімді көлік. Барлық тексерістерден уақытылы өткен. Отырасың да кете бересің.', 'images/cars/polo.jpg', 'active'),
(2, 'Nissan', 'Qashqai', 2014, 6200000, 'Отбасылық жайлы кроссовер. Жоғары клиренс, қыста өте ыңғайлы. Барлық электроникасы жұмыс істеп тұр.', 'images/cars/qashqai.jpg', 'active');
