INSERT INTO ads (user_id, brand, model, year, price, description, image_path, status) VALUES
(1, 'Toyota', 'Camry', 2020, 15500000, 'Отличное состояние, 70-й кузов. Вложений не требует. Масла и фильтры менялись вовремя. Ездили только по городу.', 'images/cars/camry.jpg', 'active'),
(2, 'Hyundai', 'Accent', 2018, 6800000, 'Очень экономичная и удобная машина для города. В такси не участвовала, маршрут только дом-работа. Торг у капота.', 'images/cars/accent.jpg', 'active'),
(1, 'Kia', 'Rio', 2019, 7200000, 'Идеальное состояние, чистый салон. Был только один хозяин. Комплект зимней резины в подарок.', 'images/cars/rio.jpg', 'active'),
(2, 'BMW', '5 Series', 2016, 12500000, 'Настоящий мужской автомобиль. Двигатель и коробка работают без нареканий. В ДТП не участвовала, в родной краске.', 'images/cars/bmw5.jpg', 'active'),
(1, 'Mercedes-Benz', 'E-Class', 2021, 28000000, 'Машина как новая, куплена у официального дилера. На гарантии. Полная комплектация, AMG пакет. Салон в идеале.', 'images/cars/mercedes_e.jpg', 'active'),
(2, 'Lada (ВАЗ)', 'Granta', 2015, 2800000, 'Надежная рабочая лошадка на каждый день. Двигатель масло не ест, ходовка мягкая. Реальному покупателю сделаю хорошую скидку.', 'images/cars/granta.jpg', 'active'),
(1, 'Lexus', 'RX 300', 2020, 27500000, 'Шикарный кроссовер. Просторный и комфортный кожаный салон в идеальном состоянии. Не бит, не крашен, любые проверки за ваш счет.', 'images/cars/rx300.jpg', 'active'),
(2, 'Toyota', 'Land Cruiser Prado', 2018, 23000000, 'Надежный внедорожник. Двигатель 4 литра. Установлена новая летняя резина. Срочная продажа в связи с необходимостью в деньгах.', 'images/cars/prado.jpg', 'active'),
(1, 'Volkswagen', 'Polo', 2017, 5500000, 'Очень экономичный автомобиль. Все ТО проходили строго по регламенту. Сел и поехал, вложений нет.', 'images/cars/polo.jpg', 'active'),
(2, 'Nissan', 'Qashqai', 2014, 6200000, 'Семейный комфортный кроссовер. Высокий клиренс, очень удобно зимой. Вся электроника работает исправно.', 'images/cars/qashqai.jpg', 'active');